<script setup>
import { computed, onMounted, ref } from 'vue'; import { answerInterview, getInterview, getInterviews } from '../api'; import NoticeBar from '../components/NoticeBar.vue'; import PageHeader from '../components/PageHeader.vue'
const sessions=ref([]),active=ref(null),answer=ref(''),notice=ref('');const current=computed(()=>active.value?.questions?.find(q=>!q.answer))
const load=async()=>sessions.value=await getInterviews();onMounted(load)
const open=async(s)=>active.value=await getInterview(s.id)
const submit=async()=>{if(!answer.value.trim())return;try{await answerInterview(active.value.id,{questionId:current.value.id,answer:answer.value});answer.value='';await open(active.value);await load();notice.value='回答已评分'}catch(e){notice.value=e.message}setTimeout(()=>notice.value='',2200)}
</script>
<template><div><NoticeBar :message="notice"/><PageHeader eyebrow="INTERVIEW LAB" title="模拟面试训练场" subtitle="围绕真实岗位生成问题，提交回答后即时得到评分和改进建议。"><RouterLink class="btn primary" to="/jobs">选择岗位练习</RouterLink></PageHeader><div class="interview-layout"><aside class="session-list"><h3>练习记录</h3><button v-for="s in sessions" :key="s.id" :class="{active:active?.id===s.id}" @click="open(s)"><span class="company-logo">{{s.job.company.slice(0,1)}}</span><span><b>{{s.job.title}}</b><small>{{s.status==='COMPLETED'?`完成 · ${s.totalScore}分`:'练习中'}}</small></span><i>›</i></button><div v-if="!sessions.length" class="empty">暂无练习记录</div></aside><section class="interview-room" v-if="active"><header><div><span class="eyebrow">{{active.job.company}}</span><h2>{{active.job.title}} · 模拟面试</h2></div><span class="status-chip">{{active.status==='COMPLETED'?'已完成':'进行中'}}</span></header><div class="question-steps"><i v-for="q in active.questions" :key="q.id" :class="{done:q.answer,current:current?.id===q.id}">{{q.questionOrder}}</i></div><div v-if="current" class="question-box"><small>QUESTION {{current.questionOrder}} / {{active.questions.length}}</small><h2>{{current.question}}</h2><textarea v-model="answer" rows="7" placeholder="结合具体经历作答，尽量包含技术方法、行动过程和结果…"></textarea><div><span>{{answer.length}} 字</span><button class="btn primary" @click="submit">提交并获取反馈 →</button></div></div><div v-else class="result-box"><span>✓</span><h2>本轮练习已完成</h2><strong>{{active.totalScore}} 分</strong><p>复盘下方各题反馈，再选择一个岗位继续练习。</p></div><div class="answer-history"><article v-for="q in active.questions.filter(q=>q.answer)" :key="q.id"><b>{{q.questionOrder}}. {{q.question}}</b><p>{{q.answer.answer}}</p><footer><span>评分 {{q.answer.score}}</span>{{q.answer.feedback}}</footer></article></div></section><section v-else class="interview-room empty-state"><span>◫</span><h2>选择一条练习记录</h2><p>进入沉浸式答题区，完成四道岗位相关问题。</p></section></div></div></template>
